{
    // Set the custom indicator properties
    IndicatorSetString(INDICATOR_SHORTNAME, "Sell Signal");
    IndicatorSetInteger(INDICATOR_DIGITS, _Digits);
    IndicatorSetInteger(INDICATOR_WIDTH1, 1);
    IndicatorSetInteger(INDICATOR_COLOR_INDEX, Green);

    //--- indicator buffers mapping
    SetIndexBuffer(0, IndicatorBuffer);

    //--- buffer visualization settings
    PlotIndexSetDouble(0, PLOT_EMPTY_VALUE, 0.0);

    //--- initialization done
    return(INIT_SUCCEEDED);
}

