    double MA_20 = iMA(_Symbol, PERIOD_M15, 20, 0, MODE_SMA, PRICE_CLOSE, 0);
    double VWMA = iCustom(_Symbol, PERIOD_M15, "Volume Weighted Moving Average", 20, PRICE_CLOSE, MODE_EMA, MODE_SMA, MODE_SMMA, 0);
    double Delta = iCustom(_Symbol, PERIOD_M15, "Cumulative Delta", 0);
    double spread = MarketInfo(_Symbol, MODE_SPREAD);
    double prev_spread = MarketInfo(_Symbol, MODE_SPREAD_PREVIOUS);

    // Set the custom indicator buffer values based on the calculated technical indicators
    for(int i = rates_total - 1; i >= 0; i--)
